  ('pukao-8b44517b-moex-00009', 'pukao-8b44517b', 'pukao-8b44517b-moex-114-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '下列國際法作為行政法法源之敘述，何者錯誤？', '["條約涉及人民之權利義務且具有法律上效力者，應送立法院審議", "條約與立法院制定之法律相牴觸時，應優先適用國內法律", "國際法須於條約或協定明定其內容，始可引用作為行政法法源", "經憲法法庭直接引用之國際公約，可以於授益行政的範圍內引用之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:06+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "406", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00010', 'pukao-8b44517b', 'pukao-8b44517b-moex-114-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '行政程序法第5條規定：「行政行為之內容應明確」，下列敘述何者正確？', '["懲處之構成要件，法律不得以抽象概念表示", "所謂內容應該明確，僅限於行政處分", "書面行政處分書雖漏未記載處分相對人之性別，但已有足資辨別之特徵者，符合明確性原則", "行政指導無需符合明確性原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:06+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "406", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
