  ('pukao-8b44517b-moex-00012', 'pukao-8b44517b', 'pukao-8b44517b-moex-114-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '行政機關應依下列何種方式行使裁量權？', '["為實現行政任務，得附加法律規定所無之條件", "為實現行政任務，得考量法律授權目的以外之因素", "應採取裁量基準所定最小干預方式，無須考量個案情節之差異", "應視個案事實情況、衡酌規範目的，進行合義務裁量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:06+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "406", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
